const fs = require('fs');
const path = require('path');

// Load environment variables from .env file
require('dotenv').config({ path: './.env' });

// Set the deployment target (e.g. production)
const TARGET = 'production';

// Build and deploy script
async function buildAndDeploy() {
  // Install dependencies
  try {
    console.log('Installing dependencies...');
    await fs.promises.readFile('.gitignore', 'utf8');
  } catch (err) {
    if (err.code === 'ENOENT') {
      console.log('Creating .gitignore file for ignoring node_modules...');
      fs.writeFileSync(path.join(__dirname, '.gitignore'), '*node_modules*');
    }
  }
  try {
    await require('child_process').execSync('npm install', { stdio: ['ignore', 'inherit', 'inherit'] });
  } catch (err) {
    console.error('Error installing dependencies:', err);
    process.exit(1);
  }

  // Run tests
  try {
    console.log('Running tests...');
    await require('child_process').execSync('npm run test', { stdio: ['ignore', 'inherit', 'inherit'] });
  } catch (err) {
    console.error('Error running tests:', err);
    process.exit(1);
  }

  // Build the application
  try {
    console.log('Building the application...');
    await require('child_process').execSync('npm run build', { stdio: ['ignore', 'inherit', 'inherit'] });
  } catch (err) {
    console.error('Error building the application:', err);
    process.exit(1);
  }

  // Deploy to production
  try {
    console.log(`Deploying to ${TARGET}...`);
    const deployCmd = `npm run deploy:${TARGET}`;
    await require('child_process').execSync(deployCmd, { stdio: ['ignore', 'inherit', 'inherit'] });
  } catch (err) {
    console.error(`Error deploying to ${TARGET}:`, err);
    process.exit(1);
  }
}

// Run the build and deploy script
buildAndDeploy().catch((err) => {
  console.error('Error:', err);
  process.exit(1);
});